import React, { useState } from 'react';
import axios from 'axios';

const SettingsView = ({ highContrast, userEmail }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [role, setRole] = useState('Analyst');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const handleCreateUser = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage({ type: '', text: '' });

    try {
      await axios.post('http://localhost:5000/signup', {
        email,
        password,
        role,
        adminEmail: userEmail
      });
      setMessage({ type: 'success', text: `Successfully created ${role} account for ${email}` });
      setEmail('');
      setPassword('');
    } catch (err) {
      setMessage({ type: 'error', text: err.response?.data?.error || 'Failed to create account' });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '2rem' }}>
      <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '2rem' }}>System Settings</h2>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem' }}>
        {/* User Management */}
        <div style={{ 
          backgroundColor: '#1e293b', 
          padding: '2rem', 
          borderRadius: '1rem', 
          border: '1px solid #334155' 
        }}>
          <h3 style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '1.5rem', color: '#38bdf8' }}>User Management</h3>
          <p style={{ color: '#94a3b8', fontSize: '0.9rem', marginBottom: '1.5rem' }}>Create new Analyst or Admin accounts for the system.</p>

          <form onSubmit={handleCreateUser} style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
            <div>
              <label style={{ display: 'block', fontSize: '0.875rem', color: '#94a3b8', marginBottom: '0.5rem' }}>Email Address</label>
              <input 
                type="email" 
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="analyst@company.com"
                style={{ 
                  width: '100%', 
                  padding: '0.75rem', 
                  backgroundColor: '#0f172a', 
                  border: '1px solid #334155', 
                  borderRadius: '0.5rem', 
                  color: 'white' 
                }} 
              />
            </div>

            <div>
              <label style={{ display: 'block', fontSize: '0.875rem', color: '#94a3b8', marginBottom: '0.5rem' }}>Password</label>
              <input 
                type="password" 
                required
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                style={{ 
                  width: '100%', 
                  padding: '0.75rem', 
                  backgroundColor: '#0f172a', 
                  border: '1px solid #334155', 
                  borderRadius: '0.5rem', 
                  color: 'white' 
                }} 
              />
            </div>

            <div>
              <label style={{ display: 'block', fontSize: '0.875rem', color: '#94a3b8', marginBottom: '0.5rem' }}>Role</label>
              <select 
                value={role}
                onChange={(e) => setRole(e.target.value)}
                style={{ 
                  width: '100%', 
                  padding: '0.75rem', 
                  backgroundColor: '#0f172a', 
                  border: '1px solid #334155', 
                  borderRadius: '0.5rem', 
                  color: 'white' 
                }}
              >
                <option value="Analyst">Analyst</option>
                <option value="Admin">Admin</option>
              </select>
            </div>

            {message.text && (
              <div style={{ 
                padding: '0.75rem', 
                borderRadius: '0.5rem', 
                fontSize: '0.875rem',
                backgroundColor: message.type === 'success' ? 'rgba(16, 185, 129, 0.1)' : 'rgba(239, 68, 68, 0.1)',
                color: message.type === 'success' ? '#10b981' : '#ef4444',
                border: `1px solid ${message.type === 'success' ? '#10b981' : '#ef4444'}`
              }}>
                {message.text}
              </div>
            )}

            <button 
              type="submit"
              disabled={loading}
              style={{ 
                padding: '0.75rem', 
                backgroundColor: '#38bdf8', 
                color: '#0f172a', 
                border: 'none', 
                borderRadius: '0.5rem', 
                fontWeight: 'bold', 
                cursor: loading ? 'not-allowed' : 'pointer' 
              }}
            >
              {loading ? 'Creating...' : 'Create User Account'}
            </button>
          </form>
        </div>

        {/* Other Settings Placeholder */}
        <div style={{ 
          backgroundColor: '#1e293b', 
          padding: '2rem', 
          borderRadius: '1rem', 
          border: '1px solid #334155',
          opacity: 0.5
        }}>
          <h3 style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>System Configuration</h3>
          <p style={{ color: '#94a3b8' }}>Additional system-wide configurations will be available here.</p>
        </div>
      </div>
    </div>
  );
};

export default SettingsView;
